using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Set up options with a known type context
var options = new JsonSerializerOptions
{
    TypeInfoResolver = MyContext.Default
};

// 1) Strongly-typed retrieval: GetTypeInfo<T>() returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Got typed metadata for Person – Kind: {personInfo.Kind}");

// 2) Probe without throwing: TryGetTypeInfo returns false if metadata isn't available
bool found = options.TryGetTypeInfo(typeof(UnknownThing), out JsonTypeInfo? info);
Console.WriteLine($"Metadata for UnknownThing available? {found}");

if (!found)
    Console.WriteLine("No metadata – branched safely, no exception thrown.");

// Also show success path of TryGetTypeInfo
bool foundPerson = options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? personInfo2);
Console.WriteLine($"Metadata for Person via TryGetTypeInfo? {foundPerson}, Kind: {personInfo2?.Kind}");

// Types
public record Person(string Name, int Age);
public class UnknownThing { public string? X { get; set; } }

[JsonSerializable(typeof(Person))]
public partial class MyContext : JsonSerializerContext;

